mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT VA.Volun_Act_No AS volunActNo, O.Organ_Name AS orgName, TO_CHAR(VA.Volun_Act_Proc_Begin, 'YYYY-MM-DD') AS volunActProcBegin, TO_CHAR(VA.Volun_Act_Proc_End, 'YYYY-MM-DD') AS volunActProcEnd, VA.Volun_Act_Point AS point,
/* 진행 상태 */ CASE WHEN SYSDATE < VA.Volun_Act_Proc_Begin THEN '진행예정' WHEN SYSDATE BETWEEN VA.Volun_Act_Proc_Begin AND VA.Volun_Act_Proc_End THEN '진행중' ELSE '종료' END AS status
FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.Volun_Act_Organ_No = O.Organ_No
1 = 1
AND VA.Volun_Act_No = #{keyword}
AND O.Organ_Name LIKE '%' || #{keyword} || '%'
ORDER BY VA.Volun_Act_No DESC
) A WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}
